  const handleGradeSelect = (grade: GradeSyllabus) => {
    setSelectedGrade(grade);
    setSelectedSubject(null);
    setCurrentView(AppView.SYLLABUS);
  };

  const initiateTopicEntry = async (topic: Topic, subjectName: string) => {
    setSelectedTopic(topic);
    // Open Quiz Modal
    setIsQuizModalOpen(true);
    setQuizLoading(true);
    setQuizResult('none');

    if (selectedGrade) {
      const q = await generateQuizQuestion(selectedGrade.grade, subjectName, topic.title);
      setCurrentQuiz(q);
    }
    setQuizLoading(false);
  };

  const handleQuizAnswer = (index: number) => {
    if (!currentQuiz) return;

    if (index === currentQuiz.correctIndex) {
      setQuizResult('correct');
      // Award Points
      setUser(prev => ({ ...prev, points: prev.points + 20 }));
      // Unlock after delay
      setTimeout(() => {
        setIsQuizModalOpen(false);
        setYunContext(`Topic: ${selectedTopic?.title}. ${selectedTopic?.description}`);
        setCurrentView(AppView.TOPIC_CONTENT);
      }, 1500);
    } else {
      setQuizResult('incorrect');
    }
  };

